// ── ROTATING WORD ANIMATIONS ──
function RotatingWord({ words }) {
  const [idx, setIdx] = useState(0);
  const [phase, setPhase] = useState("visible");
  const measRef = useRef(null);
  const [width, setWidth] = useState("auto");
  useEffect(function() {
    if (measRef.current) setWidth(measRef.current.offsetWidth + 2);
  }, [idx]);
  useEffect(function() {
    var timer = setInterval(function() {
      setPhase("exit");
      setTimeout(function() {
        setIdx(function(prev) { return (prev + 1) % words.length; });
        setPhase("enter");
        setTimeout(function() { setPhase("visible"); }, 50);
      }, 450);
    }, 3600);
    return function() { clearInterval(timer); };
  }, [words.length]);
  var wordStyle = {
    color: C.orange,
    display: "inline-block",
    transition: "opacity 0.45s ease, transform 0.45s ease",
    opacity: phase === "visible" ? 1 : 0,
    transform: phase === "exit" ? "translateY(-18px)" : phase === "enter" ? "translateY(18px)" : "translateY(0)",
  };
  return (
    <span style={{ display: "inline-block", width: width, transition: "width 0.5s cubic-bezier(0.25,0.46,0.45,0.94)", overflow: "hidden", verticalAlign: "bottom", textAlign: "left" }}>
      <span ref={measRef} style={wordStyle}>{words[idx]}</span>
    </span>
  );
}

function RotatingSentence({ sentences }) {
  const [idx, setIdx] = useState(0);
  const [phase, setPhase] = useState("visible");
  useEffect(function() {
    var timer = setInterval(function() {
      setPhase("exit");
      setTimeout(function() {
        setIdx(function(prev) { return (prev + 1) % sentences.length; });
        setPhase("enter");
        setTimeout(function() { setPhase("visible"); }, 60);
      }, 500);
    }, 4500);
    return function() { clearInterval(timer); };
  }, [sentences.length]);
  var s = sentences[idx];
  var style = {
    display: "inline-block",
    transition: "opacity 0.5s ease, transform 0.5s ease",
    opacity: phase === "visible" ? 1 : 0,
    transform: phase === "exit" ? "translateY(-20px)" : phase === "enter" ? "translateY(20px)" : "translateY(0)",
  };
  return <span style={{ display: "inline-block", overflow: "hidden" }}><span style={style}>{s.pre}<span style={{ color: C.orange }}>{s.word}</span>{s.post}</span></span>;
}

