// MAIN APP WITH ROUTING
// ════════════════════════════════════════
export default function App() {
  const { page, navigate } = useRouter();
  const [scrolled, setScrolled] = useState(false);
  useEffect(() => {
    const h = () => setScrolled(window.scrollY > 50);
    window.addEventListener("scroll", h);
    return () => window.removeEventListener("scroll", h);
  }, []);

  const pages = {
    home: <HomePage navigate={navigate} />,
    mypath: <MyPathPage navigate={navigate} />,
    why: <WhyPage navigate={navigate} />,
    process: <ProcessPage navigate={navigate} />,
    pricing: <PricingPage navigate={navigate} />,
    research: <ResearchPage />,
    team: <TeamPage />,
    faq: <FaqPage navigate={navigate} />,
    contact: <ContactPage />,
  };

  return (
    <div style={{ fontFamily: "var(--body)", color: C.slate, overflowX: "hidden", background: "linear-gradient(180deg, #fafaf7 0%, #f5f2eb 50%, #ede9de 100%)" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Oxanium:wght@400;500;600;700;800&family=Exo+2:ital,wght@0,300;0,400;0,500;0,600;0,700;0,800;1,400&display=swap');
        :root { --heading: 'Oxanium', sans-serif; --body: 'Exo 2', -apple-system, BlinkMacSystemFont, sans-serif; --ease: cubic-bezier(0.25, 0.46, 0.45, 0.94); --ease-out: cubic-bezier(0.16, 1, 0.3, 1); }
        * { margin: 0; padding: 0; box-sizing: border-box; -webkit-font-smoothing: antialiased; -moz-osx-font-smoothing: grayscale; }
        html { scroll-behavior: smooth; font-size: 16px; }
        body { text-rendering: optimizeLegibility; } p, h1, h2, h3 { text-wrap: balance; }
        ::selection { background: ${C.blue}; color: white; }
        @keyframes fadeUp { from { opacity: 0; transform: translateY(20px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
        @keyframes pageFade { from { opacity: 0; } to { opacity: 1; } }
        @keyframes pulse { 0%,100% { transform: scale(1); opacity: .4; } 50% { transform: scale(1.3); opacity: 1; } }
        @keyframes wordCycle { 0%,12% { opacity: 1; transform: translateY(0); } 13%,14% { opacity: 0; transform: translateY(-20px); } 15%,16% { opacity: 0; transform: translateY(20px); } 17%,100% { opacity: 1; transform: translateY(0); } }
        @keyframes reveal { from { opacity: 0; transform: translateY(24px); } to { opacity: 1; transform: translateY(0); } }
        .reveal { animation: reveal 0.7s var(--ease-out) both; }
        textarea::placeholder, input::placeholder { color: rgba(44,59,78,0.35); }
        button { transition: transform 0.2s var(--ease), opacity 0.2s ease; }
        button:active { transform: scale(0.97); }
        @media(max-width:768px){ .dn-mobile{display:none!important;} .dn-desktop{display:block!important;} }
        @media(min-width:769px){ .dn-desktop{display:none!important;} }
      `}</style>
      <Nav scrolled={scrolled} navigate={navigate} current={page} />
      <main key={page} style={{ animation: "pageFade .3s ease" }}>
        {pages[page] || <HomePage navigate={navigate} />}
      </main>
      <Footer navigate={navigate} />
    </div>
  );
}
